import { S } from './state.js';
import { bearing, haversine, angleDiff } from './geo.js';
import { $ } from './util.js';
import { isNative, isSim } from './platform.js';
import {
  startSetupGps, stopSetupGps, startNavGps, stopNavGps, stopAllNativeGps
} from './native-gps.js';
import {
  fuseHeading, startHeadingSensors, stopHeadingSensors, updateHeadingHealth
} from './heading.js';
import telemetry from './telemetry.js';
import { getNavSnap } from './route-geometry.js';
import {
  FUSION_GPS_WEIGHT_MIN, FUSION_GPS_WEIGHT_SPAN,
  GPS_INVALIDATE_ACC_M, GPS_INVALIDATE_ACC_STATIONARY_M, GPS_LOST_RECONVERGE_MS,
  GPS_SPEED_MAX_MPS, GPS_SPEED_ACC_TRUST_M,
  GPS_SPEED_MEAS_MIN_DIST_M, GPS_SPEED_DEVICE_MEAS_RATIO,
  GPS_SPEED_STATIONARY_DIST_M,
  GPS_SPEED_SLEW_UP_MPS2, GPS_SPEED_SLEW_DOWN_MPS2,
  GPS_SPEED_TELEPORT_M, GPS_SPEED_COAST_MAX_DT_S,
  SNAP_STATIONARY_SPD_MPS
} from './nav-constants.js';
import { isSpeedOverLimit } from './speed-limit.js';
import { tickRoundaboutHudRefresh } from './roundabout.js';
import { tickNavMap } from './nav-map.js';
import { feedGpsConverge, invalidateGpsConverge, hasEverConverged, getConvergeFailLabel } from './gps-converge.js';
import { effectiveAccM, measuredSpreadM, displayAccM } from './gps-accuracy.js';
import { isSnapLost, lostDurationMs } from './snap-quality.js';
import { tickConvergeBlocked } from './converge-telemetry.js';
import { SNAP_HEADING_MAX_AGE_MS } from './nav-constants.js';

let RENDER_POS = null;
let _navMode = false;
let _gpsLost = false;
let _lastGpsRcvMs = 0;

export function curPos(){ return RENDER_POS || S.gps; }

export function updateRenderPos(){
  if(!S.gps){ RENDER_POS = null; return; }
  const v = (S.gps.speed != null && S.gps.speed > 0.6) ? S.gps.speed : 0;
  const hdg = (S.smoothedHeading != null && !isNaN(S.smoothedHeading))
    ? S.smoothedHeading : S.gps.heading;
  if(!v || hdg == null || isNaN(hdg) || !S.fixPos){ RENDER_POS = S.gps; return; }
  const rad = Math.PI / 180;
  const now = (typeof performance !== 'undefined' ? performance.now() : Date.now());
  const dt = Math.min(1.6, Math.max(0, (now - S.fixAt) / 1000));
  const dist = v * dt;
  RENDER_POS = {
    lat: S.fixPos.lat + dist * Math.cos(hdg * rad) / 110540,
    lon: S.fixPos.lon + dist * Math.sin(hdg * rad) / (Math.cos(S.fixPos.lat * rad) * 111320),
    speed: S.gps.speed, heading: S.gps.heading, acc: S.gps.acc
  };
}

export function easeSpeed(){
  const el = $('v-speed');
  if(!el || !S.gps) return;
  const raw = S.gps.speed != null && S.gps.speed >= 0 ? S.gps.speed * 3.6 : 0;
  const target = Math.min(raw, GPS_SPEED_MAX_MPS * 3.6);
  S.dispSpeed += (target - S.dispSpeed) * 0.22;
  if(Math.abs(target - S.dispSpeed) < 0.3) S.dispSpeed = target;
  const shown = Math.round(S.dispSpeed);
  el.textContent = shown;
  el.classList.toggle('over', isSpeedOverLimit(target));
  el.classList.toggle('speed-3', shown >= 100);
}

/**
 * Фильтрация speed: плохой acc, скачки чипа, стоянка в радиусе шума.
 * @returns {{ mps: number, src: string, device: number | null, meas: number, dist: number, driftM: number, dt: number }}
 */
function resolveGpsSpeed(next, prev){
  const acc = next.acc ?? 999;
  const device = (next.speed != null && !isNaN(next.speed) && next.speed >= 0) ? next.speed : null;
  let meas = 0;
  let dist = 0;
  let dt = 0;
  if(prev){
    dt = (next.ts - prev.ts) / 1000;
    if(dt > 0.15 && dt < 14){
      dist = haversine(prev, next);
      const measFloor = acc <= GPS_SPEED_ACC_TRUST_M ? 0.6 : GPS_SPEED_MEAS_MIN_DIST_M;
      // Teleport (км за тик) — не скорость; иначе field 18-13 lat 3197
      if(dist >= measFloor && dist < GPS_SPEED_TELEPORT_M) meas = dist / dt;
    }
  }

  const driftFloor = acc <= GPS_SPEED_ACC_TRUST_M ? 0.6 : GPS_SPEED_MEAS_MIN_DIST_M;
  // Cap: иначе при acc≈60 driftM≈33 м и любой шаг 1 Гц → spd=0 (field 16-12)
  const driftM = Math.min(
    acc <= GPS_SPEED_ACC_TRUST_M
      ? driftFloor
      : Math.max(driftFloor, acc * 0.55),
    GPS_SPEED_STATIONARY_DIST_M
  );
  const base = { device, meas, dist, driftM, dt };
  const teleport = dist >= GPS_SPEED_TELEPORT_M;

  if(prev && !teleport && dist < driftM && (device == null || device < 0.5)){
    return { ...base, mps: 0, src: 'drift' };
  }

  if(meas > GPS_SPEED_MAX_MPS) meas = 0;
  const deviceAccGate = GPS_SPEED_ACC_TRUST_M * 1.6;
  let rawMps = null;
  let src = 'zero';

  // Device при нормальном acc (field: cold start gate 25→40)
  if(!teleport && device != null && device >= 0.5 && device <= GPS_SPEED_MAX_MPS &&
     acc <= deviceAccGate){
    if(!prev || meas <= 0 || device <= meas * GPS_SPEED_DEVICE_MEAS_RATIO + 1.5){
      rawMps = device;
      src = 'device';
    }
  }
  // Meas: лимит шага = max(60, v_max×dt) — при gap 6с шаг 80–250 м это езда, не шум
  // (field 18-13: step_m≈20 при spd=0 из‑за hard cap 60 + acc>40)
  const measDistCap = Math.max(60, GPS_SPEED_MAX_MPS * Math.max(dt, 0.5));
  if(rawMps == null && !teleport && meas > 0 && dist <= measDistCap){
    const accOk = acc <= GPS_SPEED_ACC_TRUST_M * 2.4 ||
      (meas >= 3 && meas <= 40 && dist >= GPS_SPEED_MEAS_MIN_DIST_M * 2);
    if(accOk){
      rawMps = S.measSpeed == null ? meas : S.measSpeed * 0.55 + meas * 0.45;
      src = 'meas';
    }
  }
  // Coast / hold при дырках — не ронять в 0 пока есть движение по координатам
  if(rawMps == null && !teleport && S.measSpeed != null && S.measSpeed > 2 &&
     dt > 0 && dt <= GPS_SPEED_COAST_MAX_DT_S){
    if(dist >= Math.max(driftM * 1.2, 8) || S.measSpeed > 3){
      rawMps = dist >= 8 && dt > 0.3
        ? Math.min(GPS_SPEED_MAX_MPS, Math.max(S.measSpeed * 0.75, (dist / dt) * 0.85))
        : S.measSpeed * 0.85;
      src = 'coast';
    }
  }
  if(rawMps == null) return { ...base, mps: 0, src: teleport ? 'teleport' : 'zero' };

  let mps = rawMps;
  if(S.measSpeed != null && dt > 0){
    const maxUp = GPS_SPEED_SLEW_UP_MPS2 * Math.max(dt, 0.35);
    const maxDn = GPS_SPEED_SLEW_DOWN_MPS2 * Math.max(dt, 0.35);
    if(mps > S.measSpeed + maxUp) mps = S.measSpeed + maxUp;
    if(mps < S.measSpeed - maxDn) mps = Math.max(0, S.measSpeed - maxDn);
  } else if((S.measSpeed == null || S.measSpeed < 2) && mps > 10 && acc > 18){
    mps = Math.min(mps, 6);
  }
  return { ...base, meas, mps, src };
}

let _onTick = () => {};
let _onVisual = () => {};

export function initGps(callbacks){
  _onTick = callbacks.onTick || _onTick;
  _onVisual = callbacks.onVisual || _onVisual;
}

export function visualLoop(){
  S.rafId = requestAnimationFrame(visualLoop);
  if(!$('hud').classList.contains('on')) return;
  telemetry.tickPerfFrame();
  updateRenderPos();
  tickNavMap();
  easeSpeed();
  tickRoundaboutHudRefresh(_onTick);
  _onVisual();
}

export function startVisualLoop(){
  if(!S.rafId) S.rafId = requestAnimationFrame(visualLoop);
}

export function stopVisualLoop(){
  if(S.rafId){ cancelAnimationFrame(S.rafId); S.rafId = null; }
}

export function getGpsDisplayAcc(){
  if(!S.gps) return null;
  return displayAccM(S.gps.acc, S._gpsSpreadBuf || []);
}

function updateGpsConvergeUI(){
  const el = $('gps-converge');
  if(el){
    el.classList.toggle('on', $('hud').classList.contains('on') && !S.gpsConverged);
  }
  const reported = S.gps?.acc != null ? Math.round(S.gps.acc) : null;
  const shown = getGpsDisplayAcc();
  const spread = S.gps ? measuredSpreadM(S._gpsSpreadBuf || []) : null;
  const failHint = getConvergeFailLabel();
  let title = 'Тап — включить GPS';
  if(S.gps){
    const parts = [];
    if(shown != null) parts.push('оценка ±' + shown + ' м');
    if(reported != null && reported !== shown) parts.push('отчёт ОС ±' + reported + ' м');
    if(spread != null) parts.push('разброс ~' + Math.round(spread) + ' м');
    if(!S.gpsConverged && failHint) parts.push('ждём: ' + failHint);
    if(parts.length) title = parts.join(' · ');
  }

  if(S.gpsConverged){
    const tag = isSim() ? ' сим' : '';
    $('s-gps').textContent = '✅ GPS' + tag + ' ±' + (shown ?? '—') + 'м';
    $('s-gps').className = 'chip ok';
  } else if(S.gps){
    $('s-gps').textContent = '⏳ GPS ±' + (shown ?? '…') + 'м';
    $('s-gps').className = 'chip';
  } else {
    $('s-gps').textContent = '⏳ GPS…';
    $('s-gps').className = 'chip';
  }
  $('s-gps').title = title;
  checkStartReady();
}

export function checkStartReady(){
  const ready = !!(S.gps && S.finish);
  $('btn-start').disabled = !ready;
  const buildBtn = $('btn-build-route');
  if(buildBtn) buildBtn.disabled = !ready;
  const goBar = $('go-bar');
  if(goBar){
    goBar.classList.toggle('hidden', !ready);
    $('setup')?.classList.toggle('has-go-bar', ready);
  }
  if(ready){
    import('./setup.js').then(m => m.updateBearingStartHint?.()).catch(() => {});
  }
}

/** Возраст последнего GPS-fix, мс (для пеленга и предупреждений). */
export function getGpsFixAgeMs(){
  if(!S.gps) return Infinity;
  if(_lastGpsRcvMs > 0) return Math.max(0, Date.now() - _lastGpsRcvMs);
  if(S.gps.ts) return Math.max(0, Date.now() - S.gps.ts);
  return Infinity;
}

export function isGpsFixStale(maxMs = 5000){
  return getGpsFixAgeMs() > maxMs;
}

function onGpsError(){
  $('s-gps').textContent = '❌ GPS';
  $('s-gps').className = 'chip err';
  invalidateGpsConverge('invalidate_error');
  if(!_gpsLost){
    _gpsLost = true;
    telemetry.log('nav', { sub: 'gps_lost' });
  }
}

export function applyGpsFix(next){
  if(S.lastPos){
    const d = haversine(S.lastPos, next);
    const dt = (next.ts - S.lastPos.ts) / 1000;
    if(d > 3 && d < 500) S.distDone += d;
    if((next.heading == null || isNaN(next.heading)) && d > 3){
      next.heading = bearing(S.lastPos, next);
      next.hdgSrc = 'move';
    } else if(d > 2 && dt > 0.3 && next.heading != null && !isNaN(next.heading)){
      // На низкой скорости GPS-курс часто врёт — предпочитаем вектор движения
      const moveHdg = bearing(S.lastPos, next);
      const spdEst = dt > 0 ? d / dt : 0;
      if(spdEst >= 1 && spdEst < 5 && angleDiff(next.heading, moveHdg) > 50){
        next.heading = moveHdg;
        next.hdgSrc = 'move';
      }
    }
  }
  const speedRes = resolveGpsSpeed(next, S.lastPos);
  S.measSpeed = speedRes.mps;
  next.speed = speedRes.mps;
  next.spdSrc = speedRes.src;
  updateHeadingHealth(next.heading, next.speed ?? S.measSpeed);
  const fused = fuseHeading(next.heading, next.speed ?? S.measSpeed);
  if(fused != null && !isNaN(fused)) next.heading = fused;

  if(next.heading != null && !isNaN(next.heading)){
    if((next.speed ?? 0) >= 3.2) S.lastReliableHeadingTs = Date.now();
    if(S.smoothedHeading == null) S.smoothedHeading = next.heading;
    else {
      const spd = next.speed ?? S.measSpeed ?? 0;
      // Стоянка: не крутить курс от шумного GPS
      if(spd < SNAP_STATIONARY_SPD_MPS){
        /* hold S.smoothedHeading */
      } else {
        const alpha = Math.min(1, FUSION_GPS_WEIGHT_MIN + spd / FUSION_GPS_WEIGHT_SPAN);
        const keep = 1 - alpha;
        const r = Math.PI / 180, d = 180 / Math.PI;
        const sx = Math.sin(S.smoothedHeading * r) * keep + Math.sin(next.heading * r) * alpha;
        const sy = Math.cos(S.smoothedHeading * r) * keep + Math.cos(next.heading * r) * alpha;
        S.smoothedHeading = (Math.atan2(sx, sy) * d + 360) % 360;
      }
    }
  }
  _lastGpsRcvMs = Date.now();
  S.lastPos = next;
  S.gps = next;
  if(!S._gpsSpreadBuf) S._gpsSpreadBuf = [];
  S._gpsSpreadBuf.push({ lat: next.lat, lon: next.lon, acc: next.acc });
  while(S._gpsSpreadBuf.length > 8) S._gpsSpreadBuf.shift();

  S.fixPos = { lat: next.lat, lon: next.lon };
  S.fixAt = (typeof performance !== 'undefined' ? performance.now() : Date.now());

  let telSnap = null;
  let navSnap = null;
  if($('hud').classList.contains('on') && S.route?.geometry){
    navSnap = getNavSnap(S.smoothedHeading);
    if(navSnap) telSnap = { lateral: navSnap.lateral, quality: S.snapQuality };
  }
  S.navLateral = navSnap?.lateral ?? null;
  const telCtx = { fix: next, snap: telSnap };

  feedGpsConverge(next, telCtx);
  const effAcc = effectiveAccM(next.acc, S._gpsSpreadBuf);
  // На стоянке не сбрасывать converge при среднем acc (field 19-03: spd=0, acc 40–120 thrash)
  const spdNow = next.speed != null && next.speed >= 0 ? next.speed : 0;
  const invAccLim = spdNow < 1.2 ? GPS_INVALIDATE_ACC_STATIONARY_M : GPS_INVALIDATE_ACC_M;
  if(effAcc != null && effAcc > invAccLim) invalidateGpsConverge('invalidate_acc', telCtx);
  if($('hud').classList.contains('on') && isSnapLost() && lostDurationMs() > GPS_LOST_RECONVERGE_MS){
    telemetry.log('nav', {
      sub: 'snap_lost_long',
      lat_off: telSnap?.lateral != null ? Math.round(telSnap.lateral) : null,
      acc: next.acc != null ? Math.round(next.acc * 10) / 10 : null,
      lost_ms: Math.round(lostDurationMs())
    });
  }
  updateGpsConvergeUI();
  tickConvergeBlocked(next, telSnap);
  if($('hud').classList.contains('on')){
    _onTick();
    if(S.viewMode !== 'hud') tickNavMap({ force: true });
  }

  const rcv = Date.now();
  if(_gpsLost){
    _gpsLost = false;
    telemetry.log('nav', { sub: 'gps_restored' });
  }
  telemetry.logFix({
    lat: next.lat, lon: next.lon, acc: next.acc,
    speed: next.speed, heading: next.heading, alt: next.alt,
    ts: next.ts, rcv,
    dev: speedRes.device,
    meas: speedRes.meas,
    spdSrc: speedRes.src,
    stepM: speedRes.dist,
    driftM: speedRes.driftM,
    stepDt: speedRes.dt
  });
  telemetry.logTrackPoint({
    lat: next.lat, lon: next.lon, acc: next.acc,
    speed: next.speed, heading: next.heading, ts: next.ts
  });
  if(navSnap) telemetry.logSnapFromResult(navSnap);
}

function stopWebGps(){
  if(S.watchId !== null && navigator.geolocation){
    navigator.geolocation.clearWatch(S.watchId);
    S.watchId = null;
  }
}

function startWebGps(){
  if(!navigator.geolocation){
    $('s-gps').textContent = '❌ Нет GPS';
    $('s-gps').className = 'chip err';
    return;
  }
  stopWebGps();
  $('s-gps').textContent = '⏳ GPS…';
  $('s-gps').className = 'chip';
  S.watchId = navigator.geolocation.watchPosition(
    pos => {
      const c = pos.coords;
      applyGpsFix({
        lat: c.latitude, lon: c.longitude,
        speed: (c.speed != null && !isNaN(c.speed) && c.speed >= 0) ? c.speed : null,
        heading: c.heading == null ? null : c.heading,
        acc: c.accuracy,
        alt: c.altitude != null && !isNaN(c.altitude) ? c.altitude : null,
        ts: pos.timestamp
      });
    },
    onGpsError,
    { enableHighAccuracy: true, timeout: 15000, maximumAge: 1000 }
  );
}

/** GPS на экране настройки (без foreground-service) */
export function startGps(){
  _navMode = false;
  startHeadingSensors();
  if(isNative()){
    $('s-gps').textContent = '⏳ GPS…';
    $('s-gps').className = 'chip';
    stopWebGps();
    startSetupGps(applyGpsFix, onGpsError).catch(onGpsError);
    return;
  }
  startWebGps();
}

/** GPS с foreground-service — при активной навигации (Android) */
export async function startNavigationGps(){
  if(!isNative()) return;
  _navMode = true;
  await startNavGps(applyGpsFix, onGpsError);
}

/** Вернуться к обычному GPS после остановки поездки */
export async function stopNavigationGps(){
  if(!isNative()) return;
  _navMode = false;
  await stopNavGps();
  await startSetupGps(applyGpsFix, onGpsError).catch(onGpsError);
}

export function isNavGpsMode(){ return _navMode; }

export async function stopAllGps(){
  stopWebGps();
  stopHeadingSensors();
  if(isNative()) await stopAllNativeGps();
}
