/** Throttle path_diverge_probe по дуге маршрута */
let _pdProbeAtS = -1e9;

/** Типы OSM highway без проезда для мото/авто (аудит после Overpass). */
export const NON_MOTOR_HIGHWAYS = new Set([
  'footway', 'pedestrian', 'steps', 'path', 'cycleway', 'bridleway', 'corridor', 'elevator'
]);

/**
 * Аудит маршрута по highwayTypes (нужен предварительный loadRouteHighwayTypes).
 * @param {object} route
 */
export function auditRouteDrivability(route){
  const types = route?.highwayTypes;
  if(!types?.length) return { ok: true, bad: [], ratio: 0, label: '' };
  const counts = {};
  for(const hw of types){
    if(!hw || !NON_MOTOR_HIGHWAYS.has(hw)) continue;
    counts[hw] = (counts[hw] || 0) + 1;
  }
  const bad = Object.entries(counts).map(([highway, n]) => ({ highway, n }));
  const totalBad = bad.reduce((s, x) => s + x.n, 0);
  const ratio = totalBad / types.length;
  const label = bad.length
    ? bad.map(x => `${x.highway}×${x.n}`).join(', ')
    : '';
  return { ok: totalBad === 0, bad, ratio, label };
}

export { isSignificantManeuver, MANEUVER_MIN_ANGLE, MANEUVER_BEND_ANGLE, MANEUVER_PASSED_M };

export function getVisibleTurnManeuvers(geom, curS, limit){
  const maxN = limit || 3;
  const sorted = geom.maneuvers
    .filter(m => isSignificantManeuver(m, geom))
    .sort((a, b) => a.s - b.s);
  const out = [];

  for(const m of sorted){
    if(curS > m.s + MANEUVER_PASSED_M) continue;
    const ahead = m.s - curS;
    const maxAhead = isInterchangeStep(m.step) ? INTERCHANGE_DIVERGE_MAX_M : 500;
    if(ahead > maxAhead) continue;
    out.push({ maneuver: m, distAhead: Math.max(0, ahead) });
    if(out.length >= maxN) break;
  }
  return out;
}

/** Построение RouteGeometry и запуск загрузки высот (не блокирует UI) */
export function ensureRouteGeometry(route){
  if(!route) return null;
  if(route.geometry?.n > 1){
    if(route.geometry.crossings == null && route.steps?.some(st => st.intersections?.length)){
      const { crossings, roundabouts } = buildCrossingsData(route.steps, route.geometry);
      route.geometry.crossings = crossings;
      route.geometry.roundabouts = roundabouts;
    }
    computeCurveSpeed(route.geometry, route);
    return route.geometry;
  }
  try{
    delete route._stepSList;
    route.geometry = buildRouteGeometry(route);
    if(route.geometry){
      const { crossings, roundabouts } = buildCrossingsData(route.steps, route.geometry);
      route.geometry.crossings = crossings;
      route.geometry.roundabouts = roundabouts;
      computeCurveSpeed(route.geometry, route);
    }
    loadRouteElevation();
    return route.geometry;
  }catch(e){
    console.warn('RouteGeometry:', e);
    route.geometry = null;
    return null;
  }
}

/** OSM traffic_signals вдоль маршрута (координаты; live-фаз нет) */
async function attachOsmSignals(route){
  const geom = route?.geometry;
  const coords = route?.coords;
  if(!geom?.n || !coords?.length) return;
  try{
    const merged = await loadMergedLayer(coords, 'signals', 'signals', 'id');
    if(!merged.items.length) return;
    const along = [];
    for(const sig of merged.items){
      const hit = projectPointToRoute(geom, { lat: sig.lat, lon: sig.lon });
      if(!hit || hit.lateral > 45) continue;
      along.push({ s: hit.s, lat: sig.lat, lon: sig.lon, id: sig.id });
    }
    along.sort((a, b) => a.s - b.s);
    geom.osmSignals = along;
    if(geom.crossings?.length){
      for(const c of geom.crossings){
        c.hasSignal = along.some(s => Math.abs(s.s - c.s) < 35);
      }
    }
    telemetry.log('nav', {
      sub: 'osm_signals_attached',
      count: along.length,
      regions: merged.regions
    });
  }catch(e){
    console.warn('osm signals:', e);
  }
}

function attachRouteGeometry(route){
  delete route._stepSList;
  ensureRouteGeometry(route);
  attachOsmSignals(route).catch(() => {});
  S.routeQuality = assessRouteQuality(route);
  resetRouteSnap();
  resetCrossingTelemetry();
  resetFuelRouteBinding();
  _pdProbeAtS = -1e9;
  loadRouteHighwayTypes(route).catch(e => console.warn('highway types:', e));
}

/**
 * Привязка snap к ближайшей точке маршрута по GPS (глобальный поиск по polyline).
 * @param {{ relaxed?: boolean }} [opts] — relaxed: без порогов lateral/heading (старт поездки).
 * @returns {boolean}
 */
export function seedSnapFromGps(opts = {}){
  const geom = S.route?.geometry;
  const gps = S.gps;
  if(!geom || !gps) return false;
  const s0 = findSForLatLon(geom, gps.lat, gps.lon);
  const p = interpolateAtS(geom, s0);
  const lat = haversine(gps, p);
  if(!opts.relaxed){
    const tan = avgTangentDeg(geom, s0, 25);
    const hdg = S.smoothedHeading;
    if(lat > REROUTE_SEED_MAX_LATERAL_M) return false;
    if(hdg != null && angleDiff(hdg, tan) > REROUTE_SEED_MAX_ANGLE_DEG) return false;
  }
  resetRouteSnap({ seedS: s0, lateral: lat });
  return true;
}

function seedSnapAfterReroute(){
  const ok = seedSnapFromGps({ relaxed: false });
  if(ok){
    telemetry.log('nav', { sub: 'reroute_seed', mode: 'strict' });
    return true;
  }
  const soft = seedSnapFromGps({ relaxed: true });
  telemetry.log('nav', {
    sub: 'reroute_seed',
    mode: soft ? 'relaxed' : 'failed',
    lateral: S.gps && S.route?.geometry
      ? Math.round(haversine(S.gps, interpolateAtS(S.route.geometry,
          findSForLatLon(S.route.geometry, S.gps.lat, S.gps.lon))) || 0)
      : null
  });
  return soft;
}

/** Фоновая сборка geometry для всех вариантов после открытия карты */
export function scheduleGeometryBuild(routes, onDone){
  if(!routes?.length){
    if(onDone) onDone();
    return;
  }
  let i = 0;
  const step = () => {
    if(i >= routes.length){
      if(onDone) onDone();
      return;
    }
    ensureRouteGeometry(routes[i]);
    i++;
    setTimeout(step, 0);
  };
  setTimeout(step, 50);
}

