/** Разбор одного маршрута OSRM в наш формат */
function highwayFromIntersections(intersections){
  for(const ix of intersections || []){
    for(const c of ix.classes || []){
      if(HIGHWAY_CLASSES.includes(c)) return c;
    }
  }
  return '';
}

function parseOsrmRoute(rt){
  const coords = rt.geometry.coordinates.map(c => [c[1], c[0]]);
  const steps = [];
  rt.legs.forEach(leg => {
    leg.steps.forEach(st => {
      const loc = st.maneuver.location;
      const m = st.maneuver;
      const intersections = (st.intersections || []).map(ix => ({
        lat: ix.location[1],
        lon: ix.location[0],
        bearings: ix.bearings || [],
        entry: ix.entry,
        in: ix.in,
        out: ix.out,
        classes: ix.classes || []
      }));
      steps.push({
        lat: loc[1], lon: loc[0],
        type: m.type,
        modifier: m.modifier,
        name: st.name || '',
        distance: st.distance,
        exit: m.exit,
        bearing_before: m.bearing_before,
        bearing_after: m.bearing_after,
        highway: highwayFromIntersections(st.intersections),
        intersections
      });
    });
  });
  const maxspeeds = parseMaxspeedsFromRoute(rt);
  const need = Math.max(0, coords.length - 1);
  while(maxspeeds.length < need) maxspeeds.push({ unknown: true });
  if(maxspeeds.length > need) maxspeeds.length = need;
  const segmentSpeeds = parseSegmentSpeedsFromRoute(rt);
  while(segmentSpeeds.length < need) segmentSpeeds.push(0);
  if(segmentSpeeds.length > need) segmentSpeeds.length = need;
  return {
    coords, steps, distance: rt.distance, duration: rt.duration,
    maxspeeds,
    segmentSpeeds,
    highwayTypes: null
  };
}

/** Запрос нескольких вариантов маршрута (для экрана настройки с картой) */
export async function fetchRouteAlternatives(){
  if(!S.gps || !S.finish) throw new Error('Нужны GPS и финиш');
  S._usedCache = false;
  const url = buildRouteRequestUrl(S.gps, S.finish, { alternatives: true });
  const r = await fetch(url);
  if(!r.ok) throw new Error('OSRM HTTP ' + r.status);
  const j = await r.json();
  return parseRouteResponse(j).map(parseOsrmRoute);
}

/** OSRM через цепочку waypoints (Яндекс rtext → наш роутер) */
export async function fetchRouteThroughWaypoints(waypoints, opts = {}){
  if(!waypoints || waypoints.length < 2) throw new Error('Нужно ≥2 точек');
  S._usedCache = false;
  const tryAlternatives = opts.alternatives ?? waypoints.length === 2;
  const url = buildRouteRequestUrl(null, null, { waypoints, alternatives: tryAlternatives });
  const r = await fetch(url);
  if(!r.ok) throw new Error('OSRM HTTP ' + r.status);
  const j = await r.json();
  const routes = parseRouteResponse(j).map(parseOsrmRoute);
  if(routes.length === 1) return routes[0];

  let best = routes[0];
  let bestScore = Infinity;
  for(const route of routes){
    try{
      await loadRouteHighwayTypes(route);
      const audit = auditRouteDrivability(route);
      const score = audit.ok ? route.distance : route.distance * (1 + audit.ratio * 20);
      if(score < bestScore){
        bestScore = score;
        best = route;
      }
    }catch(e){
      if(route.distance < best.distance) best = route;
    }
  }
  return best;
}

/** Прямая polyline между точками (быстрый старт без OSRM) */
export function buildDirectRouteFromWaypoints(waypoints){
  if(!waypoints || waypoints.length < 2) throw new Error('Нужно ≥2 точек');
  const coords = waypoints.map(w => [w.lat, w.lon]);
  let distance = 0;
  for(let i = 1; i < waypoints.length; i++){
    distance += haversine(waypoints[i - 1], waypoints[i]);
  }
  const duration = distance / (50 / 3.6);
  const steps = waypoints.map((w, i) => ({
    lat: w.lat,
    lon: w.lon,
    type: i === 0 ? 'depart' : (i === waypoints.length - 1 ? 'arrive' : 'turn'),
    modifier: '',
    name: w.label || '',
    distance: i > 0 ? haversine(waypoints[i - 1], w) : 0,
    bearing_before: i > 1 ? bearing(waypoints[i - 2], waypoints[i - 1]) : null,
    bearing_after: i < waypoints.length - 1 ? bearing(w, waypoints[i + 1]) : null,
    highway: '',
    intersections: []
  }));
  return { coords, steps, distance, duration, _direct: true };
}

/** Применить импортированный маршрут в state */
export function attachRouteFromImport(route, waypoints){
  S.routeAlternatives = [route];
  S.selectedRouteIdx = 0;
  S.route = route;
  attachRouteGeometry(S.route);
  const last = waypoints[waypoints.length - 1];
  S.finish = { lat: last.lat, lon: last.lon, label: last.label || 'Яндекс' };
  S._usedCache = false;
}

/** Выбор активного варианта из уже загруженных alternatives */
export function selectRouteIndex(idx){
  if(!S.routeAlternatives.length) return;
  S.selectedRouteIdx = Math.max(0, Math.min(S.routeAlternatives.length - 1, idx));
  S.route = S.routeAlternatives[S.selectedRouteIdx];
  resetRouteSnap();
  resetFuelRouteBinding();
  loadRouteHighwayTypes(S.route).catch(e => console.warn('highway types:', e));
}

export async function buildRoute(opts = {}){
  const { reroute = false, allowCache = true } = opts;
  if(S.routeAlternatives.length){
    selectRouteIndex(S.selectedRouteIdx);
    return;
  }
  S._usedCache = false;
  const rerouteOpts = {};
  if(reroute){
    const spd = S.gps.speed != null ? S.gps.speed : 0;
    const hdg = S.smoothedHeading;
    if(spd > 3 && hdg != null && !isNaN(hdg)){
      rerouteOpts.rerouteBearing = Math.round(hdg);
      rerouteOpts.rerouteRadius = Math.max(30, Math.round(S.gps.acc || 30));
    }
  }
  const url = buildRouteRequestUrl(S.gps, S.finish, rerouteOpts);
  try{
    const r = await fetch(url);
    if(!r.ok) throw new Error('OSRM HTTP ' + r.status);
    const j = await r.json();
    S.route = parseOsrmRoute(parseRouteResponse(j)[0]);
    attachRouteGeometry(S.route);
    if(!reroute) telemetry.log('nav', { sub: 'route_built' });
  }catch(err){
    if(!allowCache){
      throw err;
    }
    const last = loadLastRun();
    if(last && last.route && S.finish && last.finish &&
       haversine(last.finish, S.finish) < 60){
      S.route = last.route;
      delete S.route.geometry;
      attachRouteGeometry(S.route);
      if(Array.isArray(last.cameras)) S.cameras = last.cameras;
      S._usedCache = true;
      return;
    }
    throw new Error('Нет сети и нет сохранённого маршрута к этой точке');
  }
}

function classifyRerouteError(err){
  const msg = String(err?.message || err || '');
  if(err instanceof TypeError || /failed to fetch|networkerror|load failed/i.test(msg)){
    return 'network';
  }
  if(/не найден|no route|NoRoute/i.test(msg)) return 'no_route';
  if(/OSRM HTTP/i.test(msg)) return 'osrm_error';
  return 'network';
}

export async function recalcRoute(){
  if(S.rerouting) return false;
  S.rerouting = true;
  const t0 = Date.now();
  try{
    S.routeAlternatives = [];
    await buildRoute({ reroute: true, allowCache: false });
    seedSnapAfterReroute();
    clearCachedManeuver();
    telemetry.log('nav', { sub: 'reroute' });
    Array.from(S.camWarned).forEach(k => {
      if(typeof k === 'string' && k.startsWith('st_')) S.camWarned.delete(k);
    });
    await loadCameras();
    if(S.camLoadStatus === 'err'){
      console.warn('Камеры после пересчёта не загрузились');
      telemetry.log('nav', { sub: 'cameras_reload_failed' });
    }
    // Успех: cooldown вместо полного сброса — иначе thrash (field 07-21)
    S.rerouteBackoffStep = 0;
    S.rerouteBackoffUntil = Date.now() + REROUTE_SUCCESS_COOLDOWN_MS;
    return true;
  }catch(e){
    console.warn('Пересчёт не удался:', e);
    const reason = classifyRerouteError(e);
    telemetry.log('nav', {
      sub: 'reroute_failed',
      reason,
      dur_ms: Date.now() - t0
    });
    const delays = [5000, 15000, 60000];
    const step = Math.min(S.rerouteBackoffStep, 2);
    S.rerouteBackoffUntil = Date.now() + delays[step];
    S.rerouteBackoffStep = Math.min(S.rerouteBackoffStep + 1, 2);
    return false;
  }finally{
    S.rerouting = false;
  }
}

/**
 * Overpass-коридор (вне снапшота / пустой фильтр).
 * @param {number[][]} coords
 * @param {number} [aroundM]
 * @param {{ timeoutMs?: number, serverTimeoutSec?: number, maxBatches?: number, deadlineMs?: number }} [opts]
 */
async function fetchCamerasFromOverpassCorridor(coords, aroundM = 80, opts = {}){
  const samples = sampleRoutePoints(coords, 600);
  const byKey = new Map();
  const BATCH = 16;
  const timeoutMs = opts.timeoutMs ?? 22000;
  const serverTimeoutSec = opts.serverTimeoutSec ?? 18;
  const maxBatches = opts.maxBatches ?? Infinity;
  const deadline = opts.deadlineMs != null ? Date.now() + opts.deadlineMs : null;
  let batches = 0;
  for(let i = 0; i < samples.length; i += BATCH){
    if(batches >= maxBatches) break;
    if(deadline != null && Date.now() >= deadline) break;
    batches++;
    const batch = samples.slice(i, i + BATCH);
    const parts = batch.map(p =>
      `node["highway"="speed_camera"](around:${aroundM},${p.lat.toFixed(5)},${p.lon.toFixed(5)});\n` +
      `node["enforcement"="maxspeed"](around:${aroundM},${p.lat.toFixed(5)},${p.lon.toFixed(5)});`
    ).join('\n');
    const q = `[out:json][timeout:${serverTimeoutSec}];\n(\n${parts}\n);\nout body;`;
    const remain = deadline != null ? Math.max(800, deadline - Date.now()) : timeoutMs;
    const j = await overpassFetch(q, Math.min(timeoutMs, remain));
    for(const e of (j.elements || [])){
      const cam = cameraFromOverpassNode(e);
      if(!cam) continue;
      const key = cam.id || (cam.lat.toFixed(5) + ',' + cam.lon.toFixed(5));
      if(byKey.has(key)) continue;
      byKey.set(key, { lat: cam.lat, lon: cam.lon, speed: cam.speed, dir: cam.dir });
    }
  }
  return [...byKey.values()];
}

export async function loadCameras(){
  if(!S.cams || !S.route){
    S.cameras = [];
    S.camLoadStatus = S.cams ? 'idle' : 'off';
    updateCamStatusUI();
    return;
  }
  if(S._usedCache && S.cameras.length){
    S.camLoadStatus = 'ok';
    updateCamStatusUI();
    return;
  }
  const t0 = Date.now();
  const coords = S.route.coords;
  if(!coords?.length){
    S.cameras = [];
    S.camLoadStatus = 'err';
    updateCamStatusUI();
    return;
  }
  // Сразу показать кэш маршрута, пока тянется снапшот / Overpass
  const warm = loadCamerasFromRouteCache(coords);
  if(warm?.length && !S.cameras.length){
    S.cameras = warm;
    S.camLoadStatus = 'stale';
    updateCamStatusUI();
  } else {
    S.camLoadStatus = 'loading';
    updateCamStatusUI();
  }

  const CAM_AROUND_M = 150;

  // 1) Снапшоты регионов (Москва / МО / СПб…) — без Overpass в поездке
  try{
    const snap = await loadCamerasSnapshotForRoute(coords);
    if(snap?.cameras?.length){
      const filtered = filterCamerasNearRoute(snap.cameras, coords, CAM_AROUND_M);
      if(filtered.length){
        S.cameras = filtered;
        S.camLoadStatus = 'ok';
        saveCamerasToRouteCache(coords, S.cameras);
        saveLastRun();
        telemetry.log('nav', {
          sub: 'cameras_loaded',
          count: S.cameras.length,
          with_speed: S.cameras.filter(c => c.speed != null).length,
          ms: Date.now() - t0,
          mode: 'snapshot',
          snap_count: snap.count,
          snap_updated: snap.updated || undefined,
          regions: snap.regions
        });
        updateCamStatusUI();
        return;
      }
      // Снапшот есть, но коридор пуст — дотягиваем Overpass (field 07-07 count=0)
      telemetry.log('nav', {
        sub: 'cameras_snapshot_empty_corridor',
        snap_count: snap.count,
        ms: Date.now() - t0,
        regions: snap.regions,
        keep: S.cameras?.length || 0
      });
    }
  }catch(e){
    console.warn('cameras snapshot path:', e);
  }

  // 2) Overpass: при уже непустом keep — короткий probe (field 07-49 abort)
  const keepN = S.cameras?.length || 0;
  const overpassOpts = keepN > 0
    ? { timeoutMs: 4500, serverTimeoutSec: 4, maxBatches: 2, deadlineMs: 7000 }
    : { timeoutMs: 12000, serverTimeoutSec: 10, maxBatches: 6, deadlineMs: 28000 };

  try{
    const fresh = await fetchCamerasFromOverpassCorridor(coords, CAM_AROUND_M, overpassOpts);
    if(fresh.length){
      S.cameras = fresh;
      S.camLoadStatus = 'ok';
      saveCamerasToRouteCache(coords, S.cameras);
      saveLastRun();
      telemetry.log('nav', {
        sub: 'cameras_loaded',
        count: S.cameras.length,
        with_speed: S.cameras.filter(c => c.speed != null).length,
        ms: Date.now() - t0,
        mode: keepN > 0 ? 'corridor_probe' : 'corridor'
      });
    } else if(keepN > 0){
      S.camLoadStatus = 'stale';
      telemetry.log('nav', {
        sub: 'cameras_loaded',
        count: keepN,
        with_speed: S.cameras.filter(c => c.speed != null).length,
        ms: Date.now() - t0,
        mode: 'keep_after_empty',
        from_cache: true
      });
    } else {
      S.cameras = [];
      S.camLoadStatus = 'ok';
      telemetry.log('nav', {
        sub: 'cameras_loaded',
        count: 0,
        with_speed: 0,
        ms: Date.now() - t0,
        mode: 'corridor'
      });
    }
  }catch(e){
    console.warn('Камеры не загрузились:', e);
    const cached = loadCamerasFromRouteCache(coords);
    if(cached?.length){
      S.cameras = cached;
      S.camLoadStatus = 'stale';
      telemetry.log('nav', {
        sub: 'cameras_loaded',
        count: S.cameras.length,
        with_speed: S.cameras.filter(c => c.speed != null).length,
        ms: Date.now() - t0,
        mode: 'cache',
        from_cache: true
      });
    } else if(S.cameras?.length){
      S.camLoadStatus = 'stale';
      telemetry.log('nav', {
        sub: 'cameras_reload_failed',
        message: String(e?.message || e).slice(0, 120),
        ms: Date.now() - t0,
        kept: S.cameras.length
      });
    } else {
      S.cameras = [];
      S.camLoadStatus = 'err';
      telemetry.log('nav', {
        sub: 'cameras_reload_failed',
        message: String(e?.message || e).slice(0, 120),
        ms: Date.now() - t0
      });
    }
  }
  updateCamStatusUI();
}

let _nearMemoPos = null, _nearMemoVal = null, _nearIdx = 0;

/** Индекс сегмента sparse coords (OSRM), не dense geometry */
export function sparseRouteSegIdx(pos){
  const c = S.route?.coords;
  if(!c || c.length < 2 || !pos) return 0;
  let best = 0;
  let bestD = Infinity;
  for(let i = 0; i < c.length - 1; i++){
    const d = distToSegment(pos,
      { lat: c[i][0], lon: c[i][1] },
      { lat: c[i + 1][0], lon: c[i + 1][1] });
    if(d < bestD){ bestD = d; best = i; }
  }
  return best;
}

export function findNearestOnRoute(){
  if(!S.route) return null;
  const pos = curPos();
  if(!pos) return null;
  if(_nearMemoPos === pos) return _nearMemoVal;

  const geom = S.route.geometry || ensureRouteGeometry(S.route);
  if(geom){
    const snap = getRouteSnapForNav(S.smoothedHeading);
    if(snap){
      const idx = sparseRouteSegIdx({ lat: snap.lat, lon: snap.lon });
      _nearIdx = idx;
      _nearMemoPos = pos;
      _nearMemoVal = { idx, dist: snap.lateral, s: snap.s };
      return _nearMemoVal;
    }
  }

  const c = S.route.coords, n = c.length;
  const scan = (lo, hi) => {
    let best = { idx: lo, dist: Infinity };
    for(let i = lo; i < hi; i++){
      const d = distToSegment(pos,
        { lat: c[i][0], lon: c[i][1] }, { lat: c[i + 1][0], lon: c[i + 1][1] });
      if(d < best.dist){ best.dist = d; best.idx = i; }
    }
    return best;
  };
  const lo = Math.max(0, _nearIdx - 8), hi = Math.min(n - 1, _nearIdx + 60);
  let best = scan(lo, hi);
  if(best.dist > 60) best = scan(0, n - 1);
  _nearIdx = best.idx;
  _nearMemoPos = pos; _nearMemoVal = best;
  return best;
}

export function stepCoordIndex(step){
  if(step._ci != null) return step._ci;
  const c = S.route.coords;
  let bi = 0, bd = Infinity;
  for(let i = 0; i < c.length; i++){
    const d = haversine({ lat: c[i][0], lon: c[i][1] }, step);
    if(d < bd){ bd = d; bi = i; }
  }
  step._ci = bi;
  return bi;
}

function getStepSList(route){
  if(!route?.geometry || !route.steps?.length) return [];
  if(route._stepSList) return route._stepSList;
  const geom = route.geometry;
  const list = route.steps.map(st => ({
    step: st,
    s: findSForLatLon(geom, st.lat, st.lon)
  })).sort((a, b) => a.s - b.s);
  route._stepSList = list;
  return list;
}

/** OSRM-step, на котором находится curS (имя дороги «сейчас»). */
export function getCurrentRouteStepAtS(curS){
  if(curS == null || !S.route) return null;
  const list = getStepSList(S.route);
  if(!list.length) return null;
  let idx = 0;
  for(let i = 0; i < list.length; i++){
    if(curS + 1 >= list[i].s) idx = i;
    else break;
  }
  for(let i = idx; i >= 0; i--){
    if(list[i].step.name?.trim()) return list[i].step;
  }
  return list[idx]?.step || null;
}

function softNavManeuver(m){
  const st = m?.step;
  if(!st || st.type === 'depart') return false;
  if(st.type === 'arrive') return true;
  if(st.type === 'roundabout' || st.type === 'rotary' || st.type === 'exit roundabout') return true;
  // Рампы/fork — только через isSignificant (step 1), не soft-обход фильтра slight
  if(st.type === 'on ramp' || st.type === 'off ramp' || st.type === 'fork') return false;
  // end of road — только в soft-окне (иначе залипает на 10–30 мин, field 20-23/18-06)
  if(st.type === 'end of road') return true;
  const mod = st.modifier || '';
  if(mod === 'left' || mod === 'right'){
    const ang = stepTurnAngleDeg(st, m);
    if(ang != null && ang < MANEUVER_TURN_MIN_ANGLE_DEG) return false;
  }
  return !!(mod && mod !== 'straight');
}

export function findNextManeuver(){
  if(!S.route || !S.route.steps.length) return null;
  const geom = S.route.geometry;
  const snap = geom ? getNavSnap(S.smoothedHeading) : null;
  const curS = snap ? snap.s : null;
  const curIdx = snap
    ? sparseRouteSegIdx({ lat: snap.lat, lon: snap.lon })
    : (findNearestOnRoute()?.idx ?? 0);

  if(geom && curS != null){
    const sorted = [...(geom.maneuvers || [])]
      .filter(m => m.step && m.step.type !== 'depart')
      .sort((a, b) => a.s - b.s);

    function pack(m, soft){
      const along = Math.max(0, m.s - curS);
      return {
        step: m.step,
        dist: along > 0 ? along : haversine(S.gps, m.step),
        soft: !!soft
      };
    }

    // 1) значимые в окне развязки — съезды до FAR_MAX, остальное ≤800 м
    for(const m of sorted){
      if(m.step.type === 'arrive') continue;
      if(!isSignificantManeuver(m, geom)) continue;
      if(curS > m.s + MANEUVER_PASSED_M) continue;
      const along = Math.max(0, m.s - curS);
      if(m.step.type === 'end of road' && along > MANEUVER_SOFT_MAX_AHEAD_M) continue;
      const aheadMax = isInterchangeStep(m.step)
        ? INTERCHANGE_VOICE_FAR_MAX_M
        : INTERCHANGE_DIVERGE_MAX_M;
      if(along > aheadMax) continue;
      return pack(m, false);
    }

    // 1b) hint-first hybrid; на LOW OSM — не invent съезды из шумной геометрии
    if(S.routeQuality !== RouteQuality.LOW){
      const hybrid = resolveHybridPathDiverge(geom, curS, sorted, {
        isSignificant: (m) => isSignificantManeuver(m, geom)
      });
      if(curS - _pdProbeAtS >= INTERCHANGE_DIVERGE_PROBE_MIN_DS_M){
        _pdProbeAtS = curS;
        telemetry.log('nav', {
          sub: 'path_diverge_probe',
          reason: hybrid.reason,
          ok: !!hybrid.ok,
          dist: hybrid.div?.distM ?? null,
          side: hybrid.div?.side ?? null,
          hint: hybrid.hint?.kind ?? null,
          sig_ix: hybrid.sigIxAlong != null ? Math.round(hybrid.sigIxAlong) : null,
          s0: Math.round(curS)
        });
      }
      if(hybrid.ok && hybrid.pack) return hybrid.pack;
    }

    // 2) soft в 500 м (arrive тоже — иначе «финиш» на 12 км, field 18-13)
    for(const m of sorted){
      if(!softNavManeuver(m)) continue;
      if(curS > m.s + MANEUVER_PASSED_M) continue;
      const along = Math.max(0, m.s - curS);
      if(along > MANEUVER_SOFT_MAX_AHEAD_M) continue;
      return pack(m, true);
    }

    // 3) далёкие значимые (>800 м) — не рампы/fork (иначе «СЪЕЗД» на 10+ км, Варшавка)
    for(const m of sorted){
      if(m.step.type === 'arrive') continue;
      if(isInterchangeStep(m.step)) continue;
      if(!isSignificantManeuver(m, geom)) continue;
      if(curS > m.s + MANEUVER_PASSED_M) continue;
      const along = Math.max(0, m.s - curS);
      if(m.step.type === 'end of road') continue;
      if(along <= INTERCHANGE_DIVERGE_MAX_M) continue;
      return pack(m, false);
    }

    // 4) steps fallback
    for(const st of S.route.steps){
      if(st.type === 'depart') continue;
      if(stepCoordIndex(st) < curIdx) continue;
      const dist = haversine(S.gps, st);
      if(st.type !== 'arrive' && dist > MANEUVER_SOFT_MAX_AHEAD_M) continue;
      return { step: st, dist, soft: true };
    }
    return null;
  }

  for(const st of S.route.steps){
    if(st.type === 'depart') continue;
    if(stepCoordIndex(st) >= curIdx){
      return { step: st, dist: haversine(S.gps, st) };
    }
  }
  return null;
}

export function getRemainingDistance(){
  if(!S.route || !S.gps) return 0;
  const geom = S.route.geometry;
  const snap = geom ? getNavSnap(S.smoothedHeading) : null;
  if(snap) return remainingDistanceS(geom, snap);

  const near = findNearestOnRoute();
  let remaining = 0;
  if(near){
    const c = S.route.coords;
    remaining = distToSegment(S.gps,
      { lat: c[near.idx][0], lon: c[near.idx][1] },
      { lat: c[near.idx + 1][0], lon: c[near.idx + 1][1] });
    for(let i = near.idx + 1; i < c.length - 1; i++){
      remaining += haversine(
        { lat: c[i][0], lon: c[i][1] },
        { lat: c[i + 1][0], lon: c[i + 1][1] });
    }
  } else {
    remaining = haversine(S.gps, S.finish);
  }
  return remaining;
}

export function maneuverTurnAngle(step){
  if(!S.route || !step) return 0;
  const coords = S.route.coords;
  const si = stepCoordIndex(step);
  const distM = (i, j) => haversine(
    { lat: coords[i][0], lon: coords[i][1] },
    { lat: coords[j][0], lon: coords[j][1] });
  let bi = si, ai = si;
  let acc = 0;
  while(bi > 0 && acc < 25){ bi--; acc += distM(bi, bi + 1); }
  acc = 0;
  while(ai < coords.length - 1 && acc < 25){ ai++; acc += distM(ai - 1, ai); }
  if(bi >= ai) return 0;
  const bIn = bearing({ lat: coords[bi][0], lon: coords[bi][1] },
                      { lat: coords[bi + 1][0], lon: coords[bi + 1][1] });
  const bOut = bearing({ lat: coords[ai - 1][0], lon: coords[ai - 1][1] },
                       { lat: coords[ai][0], lon: coords[ai][1] });
  return ((bOut - bIn + 540) % 360) - 180;
}
